#!/usr/bin/env python3\n\"\"\"\nScript de validación: Consolidación de identidades DIAN vs SUNAT\nVerifica que el código activo de CONTA_PRO no tenga referencias a normas peruanas.\n\nUso: python3 validate_colombian_standards.py\n\"\"\"\n\nimport os\nimport sys\nimport re\nfrom pathlib import Path\nfrom collections import defaultdict\n\n# Archivos a verificar\nACTIVE_CODE_DIRS = [\n    \"src/api/routes\",\n    \"src/application\",\n    \"src/domain\",\n    \"src/infrastructure\",\n]\n\n# Exclusiones (patches viejos, migraciones, etc.)\nEXCLUDE_PATTERNS = [\n    r\"patch_.*\",\n    r\"backups.*\",\n    r\".*\\.bak$\",\n    r\"migrations/.*\",\n    r\"test.*\",\n]\n\n# Patrones SUNAT a detectar\nSUNAT_PATTERNS = {\n    \"sunat_ruc_lookup\": (r\"sunat_ruc_lookup\", \"❌ Usar: dian_rut_lookup\"),\n    \"sunat_cpe_lookup\": (r\"sunat_cpe_lookup\", \"❌ Usar: dian_antecedentes_lookup\"),\n    \"sunat_xsd\": (r\"sunat_xsd\", \"❌ Usar: dian_xsd\"),\n    \"sunat_enabled\": (r\"sunat_enabled\", \"❌ Usar: dian_enabled\"),\n    \"sunat_ruc\": (r\"sunat_ruc(?!_lookup)\", \"❌ Usar: dian_nit\"),\n    \"SunatSubmission\": (r\"SunatSubmission\", \"❌ Usar: DianSubmission\"),\n    \"SunatRealtimeVerifier\": (r\"SunatRealtimeVerifier\", \"❌ Usar: DianRealtimeVerifier\"),\n    \"PleGenerator\": (r\"PleGenerator\", \"❌ Usar: InvoiceGenerator (DIAN)\"),\n    \"SireGenerator\": (r\"SireGenerator\", \"❌ Usar: RadianSubmissionService\"),\n    \"RENIEC\": (r\"RENIEC\", \"❌ Usar: DIAN para validación de identidad\"),\n    \"PCGE_RULE_LIBRARY (sin alias)\": (r\"PCGE_RULE_LIBRARY[^\\s=]\", \"❌ Usar: PUC_RULE_LIBRARY\"),\n    \"_pcge_account_name\": (r\"_pcge_account_name(?!\\s*=)\", \"❌ Usar: _puc_account_name\"),\n}\n\n# Patrones DIAN a verificar\nDIAN_PATTERNS = {\n    \"dian_rut_lookup\": r\"dian_rut_lookup\",\n    \"dian_nit\": r\"dian_nit\",\n    \"DianSubmission\": r\"DianSubmission\",\n    \"DianRealtimeVerifier\": r\"DianRealtimeVerifier\",\n    \"PUC_RULE_LIBRARY\": r\"PUC_RULE_LIBRARY\",\n}\n\nclass ValidationResult:\n    def __init__(self):\n        self.errors = defaultdict(list)\n        self.warnings = defaultdict(list)\n        self.passed_files = []\n        self.failed_files = set()\n\n    def add_error(self, file_path, line_num, pattern_name, message):\n        self.errors[file_path].append(f\"  L{line_num}: {pattern_name} - {message}\")\n        self.failed_files.add(file_path)\n\n    def add_warning(self, file_path, line_num, pattern_name, message):\n        self.warnings[file_path].append(f\"  L{line_num}: {pattern_name} - {message}\")\n\n    def add_passed(self, file_path):\n        self.passed_files.append(file_path)\n\n    def print_report(self):\n        print(\"\\n\" + \"=\"*80)\n        print(\"VALIDACIÓN DE CONSOLIDACIÓN: DIAN vs SUNAT\")\n        print(\"=\"*80)\n\n        if self.errors:\n            print(f\"\\n❌ ERRORES ENCONTRADOS ({len(self.failed_files)} archivos):\\n\")\n            for file_path, issues in sorted(self.errors.items()):\n                print(f\"  📄 {file_path}\")\n                for issue in issues:\n                    print(issue)\n        else:\n            print(f\"\\n✅ SIN REFERENCIAS A SUNAT (0 errores)\")\n\n        if self.warnings:\n            print(f\"\\n⚠️  ADVERTENCIAS ({len(self.warnings)} archivos):\\n\")\n            for file_path, issues in sorted(self.warnings.items()):\n                print(f\"  📄 {file_path}\")\n                for issue in issues:\n                    print(issue)\n\n        print(f\"\\n✅ Archivos validados sin problemas: {len(self.passed_files)}\")\n        print(f\"❌ Archivos con errores: {len(self.failed_files)}\")\n        print(\"\\n\" + \"=\"*80)\n\n        return len(self.errors) == 0\n\ndef should_exclude(file_path):\n    \"\"\"Determinar si el archivo debe ser excluido.\"\"\"\n    path_str = str(file_path)\n    for pattern in EXCLUDE_PATTERNS:\n        if re.search(pattern, path_str):\n            return True\n    return False\n\ndef validate_file(file_path, result):\n    \"\"\"Validar un archivo individual.\"\"\"\n    try:\n        with open(file_path, \"r\", encoding=\"utf-8\", errors=\"ignore\") as f:\n            lines = f.readlines()\n    except Exception as e:\n        result.add_warning(str(file_path), 0, \"I/O Error\", str(e))\n        return\n\n    has_errors = False\n    has_content = False\n\n    for line_num, line in enumerate(lines, 1):\n        # Buscar patrones SUNAT\n        for pattern_name, (pattern, message) in SUNAT_PATTERNS.items():\n            if re.search(pattern, line, re.IGNORECASE):\n                result.add_error(str(file_path), line_num, pattern_name, message)\n                has_errors = True\n                has_content = True\n\n    # Si el archivo no tiene errores, agregarlo a pasados\n    if not has_errors and len(lines) > 0:\n        result.add_passed(str(file_path))\n\ndef main():\n    result = ValidationResult()\n    total_files = 0\n\n    for code_dir in ACTIVE_CODE_DIRS:\n        code_path = Path(code_dir)\n        if not code_path.exists():\n            print(f\"⚠️  Directorio no encontrado: {code_dir}\")\n            continue\n\n        for py_file in code_path.glob(\"**/*.py\"):\n            if should_exclude(py_file):\n                continue\n\n            total_files += 1\n            validate_file(py_file, result)\n\n    print(f\"\\n📊 Archivos procesados: {total_files}\")\n\n    # Imprimir reporte\n    passed = result.print_report()\n\n    # Retornar código de salida\n    return 0 if passed else 1\n\nif __name__ == \"__main__\":\n    sys.exit(main())\n